+/// Strip ANSI escape sequences from a string, returning plain text.
+fn strip_ansi(s: &str) -> String {
+    #[derive(Clone, Copy, PartialEq)]
+    enum State {
+        Normal,
+        Esc,
+        Csi,
+        Osc,
+    }
+    let mut state = State::Normal;
+    let mut out = String::with_capacity(s.len());
+
+    for c in s.chars() {
+        match state {
+            State::Normal => {
+                if c == '\x1b' {
+                    state = State::Esc;
+                } else {
+                    out.push(c);
+                }
+            }
+            State::Esc => {
+                if c == '[' {
+                    state = State::Csi;
+                } else if c == ']' {
+                    state = State::Osc;
+                } else {
+                    state = State::Normal;
+                }
+            }
+            State::Csi => {
+                if ('@'..='~').contains(&c) {
+                    state = State::Normal;
+                }
+            }
+            State::Osc => {
+                if c == '\x07' {
+                    state = State::Normal;
+                } else if c == '\x1b' {
+                    state = State::Esc;
+                }
+            }
+        }
+    }
+    out
+}
