+        let mut pos_120 = 0.0;
+        let mut vel_120 = 0.0;
+
+        // Simulate 1 second: 60 frames vs 120 frames
+        for _ in 0..60 {
+            (pos_60, vel_60) = spring_60.update(pos_60, vel_60, target);
+        }
+        for _ in 0..120 {
+            (pos_120, vel_120) = spring_120.update(pos_120, vel_120, target);
+        }
